#!/usr/bin/env bash
set -euo pipefail

cd /workspace/bun

# Idempotent: skip if already applied
if grep -q 'SCCACHE_BUCKET' cmake/tools/SetupSccache.cmake 2>/dev/null; then
    echo "Patch already applied."
    exit 0
fi

base64 -d <<'B64' | git apply --whitespace=fix -

B64

echo "Patch applied successfully."
